import { describe, it, expect, beforeAll, beforeEach, vi } from 'vitest';
import { useTaskStore } from '../stores/taskStore';
import { handleOrchEvent, type OrchEvent } from '../hooks/orchestration/handleOrchEvent';
import type { ToolName } from '../stores/taskStore';

// Mock the notification store to prevent side effects
vi.mock('../stores/notificationStore', () => ({
  emitOrchestrationNotification: vi.fn(),
}));

// Polyfill crypto.randomUUID for deterministic task IDs in jsdom.
// Must be in beforeAll so it runs after setup.ts which sets window.crypto.
let uuidCounter = 0;
beforeAll(() => {
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  (crypto as any).randomUUID = () => `test-uuid-${++uuidCounter}`;
});

const masterAgent: ToolName = 'claude';

function freshContext() {
  return {
    subTaskQueue: [] as string[],
    dagToFrontendId: new Map<string, string>(),
    dagCounter: 0,
  };
}

function dispatch(ev: OrchEvent, ctx = freshContext()) {
  handleOrchEvent(ev, masterAgent, ctx.subTaskQueue, ctx.dagToFrontendId, ctx.dagCounter);
  return ctx;
}

describe('handleOrchEvent', () => {
  beforeEach(() => {
    useTaskStore.getState().clearSession();
    uuidCounter = 0;
  });

  // ── phase_changed events ──────────────────────────────────

  describe('phase_changed', () => {
    it('decomposing phase sets orchestrationPhase and adds log', () => {
      dispatch({ type: 'phase_changed', phase: 'decomposing', detail: 'Breaking down task' });

      expect(useTaskStore.getState().orchestrationPhase).toBe('decomposing');
      const logs = useTaskStore.getState().orchestrationLogs;
      expect(logs.length).toBeGreaterThanOrEqual(1);
      expect(logs[logs.length - 1].level).toBe('cmd');
    });

    it('decomposing phase sets activePlan when plan_id is provided', () => {
      dispatch({
        type: 'phase_changed',
        phase: 'decomposing',
        plan_id: 'plan-123',
        master_agent: 'gemini',
      });

      const plan = useTaskStore.getState().activePlan;
      expect(plan).not.toBeNull();
      expect(plan!.task_id).toBe('plan-123');
      expect(plan!.master_agent).toBe('gemini');
    });

    it('awaiting_approval phase is set correctly', () => {
      dispatch({ type: 'phase_changed', phase: 'awaiting_approval', task_count: 5 });

      expect(useTaskStore.getState().orchestrationPhase).toBe('awaiting_approval');
    });

    it('executing phase moves pending workers to running', () => {
      // First add a pending worker task
      useTaskStore.getState().addTask({
        taskId: 'worker-1',
        prompt: 'Do something',
        toolName: 'gemini',
        status: 'pending',
        description: 'Worker task',
        startedAt: null,
        dependsOn: null,
        role: 'worker',
      });

      dispatch({ type: 'phase_changed', phase: 'executing', task_count: 1, wave_count: 1 });

      expect(useTaskStore.getState().orchestrationPhase).toBe('executing');
      expect(useTaskStore.getState().tasks.get('worker-1')!.status).toBe('running');
    });

    it('executing phase does not affect non-worker tasks', () => {
      useTaskStore.getState().addTask({
        taskId: 'master-1',
        prompt: 'Master prompt',
        toolName: 'claude',
        status: 'pending',
        description: 'Master task',
        startedAt: null,
        dependsOn: null,
        role: 'master',
      });

      dispatch({ type: 'phase_changed', phase: 'executing', task_count: 0, wave_count: 1 });

      // Master task should remain pending (not a worker)
      expect(useTaskStore.getState().tasks.get('master-1')!.status).toBe('pending');
    });

    it('reviewing phase is set correctly', () => {
      dispatch({ type: 'phase_changed', phase: 'reviewing', detail: 'Code review' });

      expect(useTaskStore.getState().orchestrationPhase).toBe('reviewing');
    });
  });

  // ── task_assigned events ──────────────────────────────────

  describe('task_assigned', () => {
    it('creates a task in the store', () => {
      const ctx = freshContext();
      dispatch(
        { type: 'task_assigned', agent: 'gemini', description: 'Fix the bug', dag_id: 'dag-1' },
        ctx,
      );

      const tasks = useTaskStore.getState().tasks;
      expect(tasks.size).toBe(1);

      const task = tasks.get('test-uuid-1')!;
      expect(task.toolName).toBe('gemini');
      expect(task.role).toBe('worker');
      expect(task.prompt).toBe('Fix the bug');
    });

    it('maps dag_id to frontend task id', () => {
      const ctx = freshContext();
      dispatch(
        { type: 'task_assigned', agent: 'claude', description: 'Write tests', dag_id: 'dag-A' },
        ctx,
      );

      expect(ctx.dagToFrontendId.get('dag-A')).toBe('test-uuid-1');
      expect(ctx.subTaskQueue).toContain('test-uuid-1');
    });

    it('sets status to running if phase is already executing', () => {
      useTaskStore.getState().setOrchestrationPhase('executing');
      const ctx = freshContext();
      dispatch(
        { type: 'task_assigned', agent: 'codex', description: 'Refactor module', dag_id: 'dag-B' },
        ctx,
      );

      const task = useTaskStore.getState().tasks.get('test-uuid-1')!;
      expect(task.status).toBe('running');
      expect(task.startedAt).not.toBeNull();
    });

    it('sets status to pending if phase is not executing', () => {
      useTaskStore.getState().setOrchestrationPhase('decomposing');
      const ctx = freshContext();
      dispatch(
        { type: 'task_assigned', agent: 'codex', description: 'Build feature', dag_id: 'dag-C' },
        ctx,
      );

      const task = useTaskStore.getState().tasks.get('test-uuid-1')!;
      expect(task.status).toBe('pending');
      expect(task.startedAt).toBeNull();
    });

    it('truncates long descriptions', () => {
      const ctx = freshContext();
      const longDesc = 'A'.repeat(80);
      dispatch(
        { type: 'task_assigned', agent: 'claude', description: longDesc, dag_id: 'dag-D' },
        ctx,
      );

      const task = useTaskStore.getState().tasks.get('test-uuid-1')!;
      expect(task.description.length).toBeLessThanOrEqual(60);
      expect(task.description.endsWith('...')).toBe(true);
    });
  });

  // ── task_completed / task_failed events ───────────────────

  describe('task_completed', () => {
    it('updates task status to completed', () => {
      const ctx = freshContext();
      dispatch(
        { type: 'task_assigned', agent: 'gemini', description: 'Task A', dag_id: 'dag-1' },
        ctx,
      );
      dispatch(
        { type: 'task_completed', dag_id: 'dag-1', summary: 'Done', exit_code: 0 },
        ctx,
      );

      const task = useTaskStore.getState().tasks.get('test-uuid-1')!;
      expect(task.status).toBe('completed');
    });

    it('logs success message', () => {
      const ctx = freshContext();
      dispatch(
        { type: 'task_assigned', agent: 'gemini', description: 'Task B', dag_id: 'dag-2' },
        ctx,
      );
      dispatch(
        { type: 'task_completed', dag_id: 'dag-2', summary: 'All good', exit_code: 0 },
        ctx,
      );

      const logs = useTaskStore.getState().orchestrationLogs;
      const completionLog = logs.find(l => l.message.includes('Completed'));
      expect(completionLog).toBeDefined();
      expect(completionLog!.level).toBe('success');
    });
  });

  describe('task_failed', () => {
    it('updates task status to failed', () => {
      const ctx = freshContext();
      dispatch(
        { type: 'task_assigned', agent: 'codex', description: 'Task C', dag_id: 'dag-3' },
        ctx,
      );
      dispatch(
        { type: 'task_failed', dag_id: 'dag-3', summary: 'Timeout', exit_code: 1 },
        ctx,
      );

      const task = useTaskStore.getState().tasks.get('test-uuid-1')!;
      expect(task.status).toBe('failed');
    });

    it('logs error message', () => {
      const ctx = freshContext();
      dispatch(
        { type: 'task_assigned', agent: 'codex', description: 'Task D', dag_id: 'dag-4' },
        ctx,
      );
      dispatch(
        { type: 'task_failed', dag_id: 'dag-4', summary: 'Build error', exit_code: 1 },
        ctx,
      );

      const logs = useTaskStore.getState().orchestrationLogs;
      const failLog = logs.find(l => l.message.includes('Failed'));
      expect(failLog).toBeDefined();
      expect(failLog!.level).toBe('error');
    });

    it('handles missing dag_id gracefully', () => {
      // Should not throw
      dispatch({ type: 'task_failed', summary: 'Unknown failure', exit_code: 1 });

      const logs = useTaskStore.getState().orchestrationLogs;
      expect(logs.find(l => l.message.includes('Failed'))).toBeDefined();
    });
  });

  // ── Other event types ─────────────────────────────────────

  describe('diffs_ready', () => {
    it('sets worktree entries in the store', () => {
      dispatch({
        type: 'diffs_ready',
        diffs: [
          { dag_id: 'dag-1', branch_name: 'feature/a', file_count: 5, additions: 20, deletions: 3 },
          { dag_id: 'dag-2', branch_name: 'feature/b', file_count: 2, additions: 8, deletions: 1 },
        ],
      });

      const entries = useTaskStore.getState().worktreeEntries;
      expect(entries.size).toBe(2);
      expect(entries.get('dag-1')!.branchName).toBe('feature/a');
      expect(entries.get('dag-2')!.additions).toBe(8);
    });
  });

  describe('decomposition_failed', () => {
    it('logs error and sets resultSummary on master task', () => {
      useTaskStore.getState().addTask({
        taskId: 'master-1',
        prompt: 'Orchestrate',
        toolName: 'claude',
        status: 'running',
        description: 'Master',
        startedAt: Date.now(),
        dependsOn: null,
        role: 'master',
      });

      dispatch({ type: 'decomposition_failed', error: 'JSON parse error' });

      const logs = useTaskStore.getState().orchestrationLogs;
      expect(logs.find(l => l.message === 'JSON parse error')).toBeDefined();

      const masterTask = useTaskStore.getState().tasks.get('master-1')!;
      expect(masterTask.resultSummary).toBe('JSON parse error');
    });
  });

  describe('info', () => {
    it('adds an info log entry', () => {
      dispatch({ type: 'info', message: 'Starting merge' });

      const logs = useTaskStore.getState().orchestrationLogs;
      expect(logs.length).toBe(1);
      expect(logs[0].level).toBe('info');
      expect(logs[0].message).toBe('Starting merge');
    });
  });

  describe('wave_progress', () => {
    it('logs wave progress', () => {
      dispatch({ type: 'wave_progress', current: 2, total: 3 });

      const logs = useTaskStore.getState().orchestrationLogs;
      expect(logs.find(l => l.message.includes('Wave 2/3'))).toBeDefined();
    });
  });

  describe('question', () => {
    it('sets pending question when plan_id is provided', () => {
      dispatch({
        type: 'question',
        agent: 'gemini',
        content: 'Which database?',
        plan_id: 'plan-1',
      });

      const q = useTaskStore.getState().pendingQuestion;
      expect(q).not.toBeNull();
      expect(q!.sourceAgent).toBe('gemini');
      expect(q!.content).toBe('Which database?');
    });
  });

  describe('question_answered', () => {
    it('clears pending question', () => {
      useTaskStore.getState().setPendingQuestion({
        questionId: 'q1',
        sourceAgent: 'gemini',
        content: 'Which DB?',
        planId: 'plan-1',
      });

      dispatch({ type: 'question_answered', agent: 'gemini' });

      expect(useTaskStore.getState().pendingQuestion).toBeNull();
    });
  });
});

import { useTaskStore, type ToolName, type TaskStatus, type WorktreeReviewEntry } from '../../stores/taskStore';
import { emitOrchestrationNotification } from '../../stores/notificationStore';
import { asToolName } from '../../lib/agents';

/* ── Structured orchestrator event handler ───────────────── */

export type OrchEvent =
  | { type: 'phase_changed'; phase: string; detail?: string; task_count?: number; wave_count?: number; plan_id?: string; master_agent?: string }
  | { type: 'task_assigned'; agent: string; description: string; prompt?: string; dag_id?: string }
  | { type: 'task_completed'; dag_id?: string; summary?: string; exit_code?: number }
  | { type: 'task_failed'; dag_id?: string; summary?: string; exit_code?: number; agent?: string; failure_reason?: string }
  | { type: 'decomposition_failed'; error: string }
  | { type: 'wave_progress'; current: number; total: number }
  | { type: 'task_skipped'; dag_id: string; reason: string }
  | { type: 'task_retrying'; dag_id: string; attempt: number; max_retries: number }
  | { type: 'task_fallback'; dag_id: string; from_agent: string; to_agent: string }
  | { type: 'rate_limited'; dag_id: string; wait_seconds: number }
  | { type: 'rate_limit_action_needed'; agent: string; remaining_tasks: Array<{ dag_id: string; description: string; prompt: string }>; available_agents: string[]; plan_id: string; resets_at?: string }
  | { type: 'master_timeout'; timeout_minutes: number }
  | { type: 'worker_timeout'; timeout_minutes: number }
  | { type: 'review_timeout'; timeout_minutes: number }
  | { type: 'question'; agent: string; content: string; plan_id?: string }
  | { type: 'question_answered'; agent: string }
  | { type: 'dispatch_error'; dag_id: string; error: string }
  | { type: 'worker_output'; dag_id: string; line: string }
  | { type: 'worker_started'; dag_id: string; process_id: string }
  | { type: 'diffs_ready'; diffs: Array<{ dag_id: string; branch_name: string; file_count: number; additions: number; deletions: number }> }
  | { type: 'info'; message: string };

const lastOutputUpdateByDag = new Map<string, number>();

export function handleOrchEvent(
  ev: OrchEvent,
  masterAgent: ToolName,
  subTaskQueue: string[],
  dagToFrontendId: Map<string, string>,
  dagCounter: number,
) {
  const store = useTaskStore.getState();
  type LogLevel = 'info' | 'success' | 'warn' | 'cmd' | 'error';
  const log = (level: LogLevel, message: string) =>
    store.addOrchestrationLog({ agent: masterAgent, level, message });

  switch (ev.type) {
    case 'phase_changed': {
      const phase = ev.phase;
      if (phase === 'decomposing') {
        lastOutputUpdateByDag.clear();
        store.setOrchestrationPhase('decomposing');
        // Set activePlan early from enriched event so it's available before awaiting_approval
        if (ev.plan_id) {
          store.setActivePlan({
            task_id: ev.plan_id,
            master_agent: ev.master_agent ? asToolName(ev.master_agent) : masterAgent,
            master_process_id: null,
          });
        }
        log('cmd', `Phase 1: ${ev.detail || 'Decomposing'}`);
      } else if (phase === 'awaiting_approval') {
        store.setOrchestrationPhase('awaiting_approval');
        log('info', `${ev.task_count} sub-tasks ready for approval`);
      } else if (phase === 'executing') {
        store.setOrchestrationPhase('executing');
        // Move pending worker tasks to 'waiting' (queued) — they'll transition
        // to 'running' when their worker_started event arrives from the backend
        for (const [id, task] of store.tasks) {
          if (task.status === 'pending' && task.role === 'worker') {
            store.updateTaskStatus(id, 'waiting');
          }
        }
        log('cmd', `Phase 2: Executing ${ev.task_count ?? ''} sub-tasks in ${ev.wave_count ?? ''} wave(s)`);
      } else if (phase === 'reviewing') {
        store.setOrchestrationPhase('reviewing');
        log('cmd', `Phase 3: ${ev.detail || 'Reviewing'}`);
      } else if (phase === 'completed') {
        store.setOrchestrationPhase('completed');
        // Mark master task as completed
        const currentTasks = useTaskStore.getState().tasks;
        for (const [id, t] of currentTasks) {
          if (t.role === 'master' && t.status !== 'completed') {
            store.updateTaskStatus(id, 'completed');
            break;
          }
        }
        log('success', 'Orchestration completed');
      }
      break;
    }

    case 'task_assigned': {
      const agent = ev.agent;
      const desc = ev.description;
      const prompt = ev.prompt || desc; // Full prompt from backend, fallback to description
      const subId = crypto.randomUUID();
      const phase2Already = store.orchestrationPhase === 'executing';
      store.addTask({
        taskId: subId,
        prompt,
        toolName: asToolName(agent),
        status: phase2Already ? 'running' : 'pending',
        description: desc.length > 60 ? desc.slice(0, 57) + '...' : desc,
        startedAt: phase2Already ? Date.now() : null,
        dependsOn: null,
        role: 'worker',
      });
      subTaskQueue.push(subId);
      dagToFrontendId.set(ev.dag_id ?? `t${dagCounter + 1}`, subId);
      log('info', `Assigned to ${agent}: ${desc}`);
      break;
    }

    case 'task_completed':
    case 'task_failed': {
      if (!ev.dag_id) {
        console.warn(`${ev.type} received without dag_id — cannot match to frontend task`);
      }
      const status: TaskStatus = ev.type === 'task_completed' ? 'completed' : 'failed';
      const targetId = ev.dag_id ? dagToFrontendId.get(ev.dag_id) : undefined;
      if (!targetId && ev.dag_id) {
        console.warn(`Unmatched dag_id in ${ev.type}: ${ev.dag_id}`);
      }
      if (targetId) {
        store.updateTaskStatus(targetId, status);
        // Clean up queue entry if present
        const queueIdx = subTaskQueue.findIndex(id => dagToFrontendId.get(ev.dag_id!) === id);
        if (queueIdx !== -1) subTaskQueue.splice(queueIdx, 1);
      }
      const summary = ev.summary || '';
      // Store failure detail on the task for inspection in TaskDetail
      if (ev.type === 'task_failed' && targetId && summary) {
        store.updateTaskResult(targetId, summary.slice(0, 500));
      }
      if (ev.type === 'task_failed') {
        // Log detailed failure info — agent, exit code, failure reason, and full summary
        const agent = (ev as { agent?: string }).agent || 'unknown';
        const reason = (ev as { failure_reason?: string }).failure_reason || '';
        log('error', `[${agent}] Failed (exit ${ev.exit_code})`);
        if (reason) log('error', `Failure reason: ${reason}`);
        if (summary) log('error', `Output:\n${summary.slice(0, 500)}`);
      } else {
        log('success', `Completed (exit ${ev.exit_code}): ${summary}`);
      }
      // Emit notification for task completion/failure
      emitOrchestrationNotification(
        ev.type === 'task_completed' ? 'success' : 'error',
        ev.type === 'task_completed' ? 'Task Completed' : 'Task Failed',
        summary.slice(0, 100) || undefined,
        targetId ? { label: 'View', taskId: targetId } : undefined,
      );
      break;
    }

    case 'wave_progress': {
      log('info', `\u27D0 Wave ${ev.current}/${ev.total}`);
      break;
    }

    case 'task_skipped': {
      const dagId = ev.dag_id;
      const frontendId = dagToFrontendId.get(dagId);
      if (frontendId) {
        store.updateTaskStatus(frontendId, 'blocked');
        const qIdx = subTaskQueue.indexOf(frontendId);
        if (qIdx !== -1) subTaskQueue.splice(qIdx, 1);
      }
      log('warn', `Skipping ${dagId}: ${ev.reason}`);
      break;
    }

    case 'task_retrying': {
      const dagId = ev.dag_id;
      const frontendId = dagToFrontendId.get(dagId);
      if (frontendId) {
        store.updateTaskStatus(frontendId, 'retrying');
        const qIdx = subTaskQueue.indexOf(frontendId);
        if (qIdx !== -1) subTaskQueue.splice(qIdx, 1);
        subTaskQueue.push(frontendId);
      }
      log('info', `Retrying ${dagId} (attempt ${ev.attempt}/${ev.max_retries})`);
      break;
    }

    case 'task_fallback': {
      const dagId = ev.dag_id;
      const newAgent = ev.to_agent;
      const frontendId = dagToFrontendId.get(dagId);
      if (frontendId) {
        const task = store.tasks.get(frontendId);
        if (task) {
          const newTasks = new Map(store.tasks);
          newTasks.set(frontendId, { ...task, toolName: asToolName(newAgent), status: 'falling_back' });
          useTaskStore.setState({ tasks: newTasks });
        }
      }
      log('info', `Falling back: ${dagId} reassigned from ${ev.from_agent} to ${newAgent}`);
      break;
    }

    case 'rate_limited': {
      log('warn', `Rate limited on ${ev.dag_id} — waiting ${ev.wait_seconds}s`);
      break;
    }

    case 'rate_limit_action_needed': {
      const agent = asToolName(ev.agent);
      log('error', `${ev.agent} rate limit reached! ${ev.remaining_tasks.length} tasks remaining.`);
      store.setRateLimitAlert({
        agent,
        remainingTasks: ev.remaining_tasks.map(t => ({ dagId: t.dag_id, description: t.description, prompt: t.prompt })),
        availableAgents: ev.available_agents.map(a => asToolName(a)),
        planId: ev.plan_id,
        resetsAt: ev.resets_at,
      });
      emitOrchestrationNotification(
        'warning',
        `${ev.agent} Rate Limit Reached`,
        `${ev.remaining_tasks.length} tasks need reassignment`,
        { label: 'Review' },
      );
      break;
    }

    case 'master_timeout':
    case 'worker_timeout':
    case 'review_timeout': {
      log('error', `${ev.type.replace('_', ' ')} after ${ev.timeout_minutes} minutes`);
      break;
    }

    case 'question': {
      log('info', `${ev.agent} asks: ${ev.content}`);
      // Set pending question so the UI shows the answer prompt
      if (ev.plan_id) {
        store.setPendingQuestion({
          questionId: `q-${Date.now()}`,
          sourceAgent: ev.agent,
          content: ev.content,
          planId: ev.plan_id,
        });
      }
      // Notify user — especially useful when app is in background
      emitOrchestrationNotification(
        'warning',
        `${ev.agent} has a question`,
        String(ev.content).slice(0, 100),
        { label: 'Answer' },
      );
      break;
    }

    case 'question_answered': {
      log('info', `Master answered ${ev.agent}'s question`);
      store.setPendingQuestion(null);
      break;
    }

    case 'dispatch_error': {
      log('error', `Dispatch failed for ${ev.dag_id}: ${ev.error}`);
      break;
    }

    case 'info': {
      log('info', ev.message);
      break;
    }

    case 'worker_output': {
      const frontendId = dagToFrontendId.get(ev.dag_id);
      if (frontendId) {
        const now = Date.now();
        const lastUpdate = lastOutputUpdateByDag.get(ev.dag_id) ?? 0;
        if (now - lastUpdate > 500) {
          lastOutputUpdateByDag.set(ev.dag_id, now);
          store.updateTaskOutputLine(frontendId, ev.line);
        }
      }
      break;
    }

    case 'worker_started': {
      const frontendId = dagToFrontendId.get(ev.dag_id);
      if (frontendId) {
        store.updateTaskStatus(frontendId, 'running');
      }
      break;
    }

    case 'diffs_ready': {
      const entries = new Map<string, WorktreeReviewEntry>();
      for (const d of ev.diffs) {
        entries.set(d.dag_id, {
          dagId: d.dag_id,
          branchName: d.branch_name,
          fileCount: d.file_count,
          additions: d.additions,
          deletions: d.deletions,
        });
      }
      store.setWorktreeEntries(entries);
      log('info', `Diffs ready: ${ev.diffs.length} worktrees`);
      break;
    }

    case 'decomposition_failed': {
      log('error', ev.error);
      // Use fresh state to find the master task
      const currentTasks = useTaskStore.getState().tasks;
      for (const [id, t] of currentTasks) {
        if (t.role === 'master') {
          store.updateTaskResult(id, ev.error);
          break;
        }
      }
      break;
    }
  }
}

import { useCallback } from 'react';
import { Channel } from '@tauri-apps/api/core';
import { commands } from '../../bindings';
import type { OutputEvent } from '../../bindings';
import {
  emitProcessOutput,
  emitLocalProcessMessage,
  useProcessStore,
} from '../useProcess';
import { useTaskStore, type ToolName, type TaskStatus, type OrchestratorConfig } from '../../stores/taskStore';
import { handleOrchEvent } from './handleOrchEvent';

/**
 * Hook that provides the `dispatchOrchestratedTask` function for multi-agent orchestration.
 */
export function useOrchestratedDispatch() {
  const dispatchOrchestratedTask = useCallback(
    async (
      prompt: string,
      projectDir: string,
      orchestratorConfig: OrchestratorConfig,
    ): Promise<Map<ToolName, string>> => {
      const results = new Map<ToolName, string>();

      // Create channel for orchestration output (all phases stream through this)
      const channel = new Channel<OutputEvent>();
      const orchestrationId = crypto.randomUUID();

      // Buffer for capturing agent result text to attach to completing tasks
      let lastResultText = '';
      // Ordered queue of sub-task IDs for matching sequential completion messages
      const subTaskQueue: string[] = [];
      // Map DAG IDs (t1, t2, ...) to frontend task IDs — assigned in order
      const dagToFrontendId = new Map<string, string>();
      let dagCounter = 0;

      channel.onmessage = (msg: OutputEvent) => {
        if (msg.event === 'exit') {
          const code = Number(msg.data);
          useProcessStore.getState()._updateStatus(
            orchestrationId,
            code === 0 ? 'completed' : 'failed',
            code,
          );
          emitProcessOutput(orchestrationId, msg);
          return;
        }
        emitProcessOutput(orchestrationId, msg);

        if (msg.event === 'stdout' && msg.data) {
          const line = msg.data;
          const masterAgent = orchestratorConfig.masterAgent;

          // --- Structured orchestrator events (@@orch:: prefix) ---
          if (line.startsWith('@@orch::')) {
            try {
              const ev = JSON.parse(line.slice(8));
              handleOrchEvent(ev, masterAgent, subTaskQueue, dagToFrontendId, dagCounter);
              if (ev.type === 'task_assigned') dagCounter++;
            } catch (e) { console.error('Malformed orch event:', e); }
            return;
          }

          // --- NDJSON agent output (Claude/Gemini result events) ---
          if (line.startsWith('{')) {
            try {
              const ev = JSON.parse(line);
              if (ev.type === 'result') {
                const resultText = ev.result || ev.response;
                let isDecompositionJson = false;
                if (resultText) {
                  try {
                    const parsed = typeof resultText === 'string' ? JSON.parse(resultText) : null;
                    if (parsed && Array.isArray(parsed.tasks) && parsed.tasks[0]?.agent) {
                      isDecompositionJson = true;
                    } else if (parsed && Array.isArray(parsed.sub_tasks) && parsed.sub_tasks[0]?.assigned_agent) {
                      isDecompositionJson = true;
                    }
                  } catch (e) { /* not decomposition JSON */ }
                }
                if (resultText && !isDecompositionJson) {
                  lastResultText = resultText.length > 800 ? resultText.slice(0, 797) + '...' : resultText;
                  if (resultText.length < 500) {
                    useTaskStore.getState().addOrchestrationLog({
                      agent: masterAgent,
                      level: 'success',
                      message: resultText.length > 200 ? resultText.slice(0, 200) + '...' : resultText,
                    });
                  }
                }
                const inputTokens = ev.usage?.input_tokens ?? ev.stats?.input_tokens ?? null;
                const outputTokens = ev.usage?.output_tokens ?? ev.stats?.output_tokens ?? null;
                const totalTokens = ev.usage?.total_tokens ?? ev.stats?.total_tokens
                  ?? (inputTokens != null && outputTokens != null ? inputTokens + outputTokens : null);
                useTaskStore.getState().updateAgentContext(masterAgent, {
                  toolName: masterAgent,
                  inputTokens,
                  outputTokens,
                  totalTokens,
                  costUsd: typeof ev.total_cost_usd === 'number' ? ev.total_cost_usd : null,
                  status: ev.is_error ? 'failed' : 'completed',
                });
              }
            } catch (e) { /* not valid JSON */ }
          }
          // Skip all other raw text (MCP warnings, echoed prompts, verbose agent output)
        }
      };

      // Register orchestration as a single process in frontend
      const store = useProcessStore.getState();
      const newProcesses = new Map(store.processes);
      const description = prompt.length > 60 ? prompt.slice(0, 57) + '...' : prompt;
      newProcesses.set(orchestrationId, {
        taskId: orchestrationId,
        cmd: `orchestration: ${description}`,
        status: 'running',
        channel,
        startedAt: Date.now(),
        hasOutput: false,
        lastEventAt: Date.now(),
        lastOutputPreview: 'Master orchestration started. Worker output will stream here.',
      });
      useProcessStore.setState({
        processes: newProcesses,
        activeProcessId: orchestrationId,
      });

      emitLocalProcessMessage(orchestrationId, `$ ${prompt}`);

      try {
        // Convert frontend config format (camelCase) to backend format (snake_case)
        const backendConfig = {
          agents: orchestratorConfig.agents.map(a => ({
            tool_name: a.toolName,
            sub_agent_count: a.subAgentCount,
            is_master: a.isMaster,
          })),
          master_agent: orchestratorConfig.masterAgent,
        };

        const result = await commands.dispatchOrchestratedTask(
          prompt,
          projectDir,
          backendConfig,
          channel,
        );

        if (result.status === 'ok') {
          const plan = result.data;
          const taskState = useTaskStore.getState();

          // Determine final phase status
          const phaseStr = plan.phase as string;
          const isFailure = phaseStr === 'Failed';
          const finalStatus: TaskStatus = isFailure ? 'failed' : 'completed';

          // Update the initial orchestration task that was added immediately at launch
          // Find it: it's the task with status 'running' matching the prompt
          const currentTasks = taskState.tasks;
          for (const [id, t] of currentTasks) {
            if (t.status === 'running' && t.prompt === prompt) {
              taskState.updateTaskStatus(id, finalStatus);
              // Attach final result summary to the master task
              if (lastResultText) {
                taskState.updateTaskResult(id, lastResultText);
                lastResultText = '';
              }
              break;
            }
          }

          // Add any sub-tasks that weren't already tracked via real-time events
          for (const subTask of plan.sub_tasks) {
            results.set(subTask.assigned_agent as ToolName, subTask.id);
            const alreadyTracked = Array.from(taskState.tasks.values()).some(
              t => t.prompt === subTask.prompt
            );
            if (!alreadyTracked) {
              taskState.addTask({
                taskId: subTask.id,
                prompt: subTask.prompt,
                toolName: subTask.assigned_agent as ToolName,
                status: 'completed',
                description: subTask.prompt.length > 60 ? subTask.prompt.slice(0, 57) + '...' : subTask.prompt,
                startedAt: Date.now(),
                dependsOn: null,
              });
            }
          }

          // Store active plan for /clear command
          taskState.setActivePlan({
            task_id: plan.task_id,
            master_agent: plan.master_agent,
            master_process_id: plan.master_process_id,
          });

          // Mark orchestration phase as completed or failed
          taskState.setOrchestrationPhase(isFailure ? 'failed' : 'completed');

          useProcessStore.getState()._updateStatus(orchestrationId, finalStatus, isFailure ? -1 : 0);
        } else {
          console.error('Orchestration failed:', result.error);
          useProcessStore.getState()._updateStatus(orchestrationId, 'failed', -1);
          useTaskStore.getState().setOrchestrationPhase('failed');
          throw new Error(result.error);
        }
      } catch (e) {
        console.error('Orchestration error:', e);
        useProcessStore.getState()._updateStatus(orchestrationId, 'failed', -1);
        const taskState = useTaskStore.getState();
        taskState.setOrchestrationPhase('failed');

        // Mark any running tasks as failed
        for (const [id, t] of taskState.tasks) {
          if (t.status === 'running') {
            taskState.updateTaskStatus(id, 'failed');
          }
        }

        throw e;
      }

      return results;
    },
    [],
  );

  return { dispatchOrchestratedTask };
}

